import { useRef } from "react";
import Dashboard from "./componets/dashboard";

export default function App() {
  const audioRef = useRef(null);

  const playAlertSound = () => {
    // Create a simple beep sound using Web Audio API (resilient)
    try {
      const AudioCtx = window.AudioContext || window.webkitAudioContext;
      if (!AudioCtx) throw new Error("Web Audio API not supported");
      const audioContext = new AudioCtx();
      // Some browsers start in 'suspended' state — resume before playing
      if (audioContext.state === "suspended") {
        audioContext.resume().catch(() => {});
      }

      const oscillator = audioContext.createOscillator();
      const gainNode = audioContext.createGain();

      oscillator.type = "sine";
      oscillator.frequency.value = 800;
      gainNode.gain.setValueAtTime(0.3, audioContext.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.5);

      oscillator.connect(gainNode);
      gainNode.connect(audioContext.destination);

      oscillator.start();
      oscillator.stop(audioContext.currentTime + 0.5);
      // close context after short delay to free resources
      setTimeout(() => {
        try { audioContext.close(); } catch (e) {}
      }, 1000);
    } catch (err) {
      // Fallback: use simple alert sound via <audio> element if WebAudio fails
      try {
        const beep = new Audio();
        // small silent fallback; browsers may block autoplay but this is best-effort
        beep.src = "data:audio/wav;base64,UklGRiQAAABXQVZFZm10IBAAAAABAAEAQB8AAIA+AAACABAAZGF0YQAAAAA=";
        beep.play().catch(() => {});
      } catch (e) {
        // last resort: no-op
        console.error("Failed to play fallback beep:", e);
      }
    }
  };

  return (
    <>
      <div className="alert-banner">
        🚨 AMBULANCE ON THE WAY – PLEASE CLEAR THE ROUTE
      </div>
      <Dashboard onPlaySound={playAlertSound} />
      <audio ref={audioRef} />
    </>
  );
}

